#include <stdio.h>
#include <stdlib.h>

int main() {
 FILE *pipe_fp;
 char buffer[256];
 int exit_status;

 // Open pipe to read from 'ls -l' command
 pipe_fp = popen("ls -l", "r");
 if (pipe_fp == NULL) {
 perror("popen failed");
 return 1;
 }

 // Read command output line by line
 while (fgets(buffer, sizeof(buffer), pipe_fp) != NULL) {
 printf("%s", buffer);
 }

 // Close pipe and get exit status
 exit_status = pclose(pipe_fp);

 // Check if command executed successfully
 if (WIFEXITED(exit_status)) {
 printf("\nCommand exit code: %d\n", 
 WEXITSTATUS(exit_status));
 } else {
 printf("Command terminated abnormally\n");
 }

 return 0;
}

#include <stdio.h>
#include <stdlib.h>

int main() {
 FILE *pipe_fp;
 const char *input_data = "line 1\nline 2\nline 3\n";
 int exit_status;

 // Open pipe to write to 'wc -l' command
 pipe_fp = popen("wc -l", "w");
 if (pipe_fp == NULL) {
 perror("popen failed");
 return 1;
 }

 // Write data to command's stdin
 fprintf(pipe_fp, "%s", input_data);

 // Close pipe - IMPORTANT: close before checking status
 exit_status = pclose(pipe_fp);

 // Check exit status
 if (WIFEXITED(exit_status)) {
 printf("Command exit code: %d\n", 
 WEXITSTATUS(exit_status));
 }

 return 0;
}

#include <stdio.h>
#include <stdlib.h>
#include <errno.h>
#include <sys/wait.h>

int main() {
 FILE *pipe_fp;
 int status;

 pipe_fp = popen("ls /nonexistent", "r");
 if (pipe_fp == NULL) {
 perror("popen");
 return 1;
 }

 // Read output (will be error message)
 char buffer[256];
 while (fgets(buffer, sizeof(buffer), pipe_fp) != NULL) {
 fprintf(stderr, "%s", buffer);
 }

 // Close pipe and get status
 status = pclose(pipe_fp);

 // Error handling for pclose
 if (status == -1) {
 perror("pclose error");
 } else if (WIFEXITED(status)) {
 int exit_code = WEXITSTATUS(status);
 printf("Command exited with code: %d\n", exit_code);
 } else if (WIFSIGNALED(status)) {
 printf("Command killed by signal: %d\n", WTERMSIG(status));
 }

 return 0;
}
